#[derive(Debug, Clone, PartialEq, Eq)]
pub enum HvfVcpuRunnerError {
    Backend(BackendError),
    CpuTemplate(HvfArm64CpuTemplateVcpuError),
    Gic(HvfGicError),
    GicIccRegisterRestore(HvfArm64GicIccRegisterRestoreError),
    DebugTrapRestore(HvfArm64VcpuDebugTrapRestoreError),
    GeneralRegisterRestore(HvfArm64VcpuGeneralRegisterRestoreError),
    PendingInterruptRestore(HvfArm64VcpuPendingInterruptRestoreError),
    SimdFpRestore(HvfArm64VcpuSimdFpRestoreError),
    SystemRegisterRestore(HvfArm64VcpuSystemRegisterRestoreError),
    SmePRegisterCapture(HvfArm64VcpuSmePRegisterCaptureError),
    SmeZRegisterCapture(HvfArm64VcpuSmeZRegisterCaptureError),
    SmeZaRegisterCapture(HvfArm64VcpuSmeZaRegisterCaptureError),
    SmeZt0RegisterCapture(HvfArm64VcpuSmeZt0RegisterCaptureError),
    SnapshotTimerPolicy(HvfArm64SnapshotTimerPolicyError),
    SnapshotTimerRestore(HvfArm64SnapshotTimerRestoreError),
    SnapshotOptionalState(HvfArm64SnapshotOptionalStateRejection),
    SnapshotRestoreCompatibility(HvfArm64SnapshotV1CompatibilityError),
    SnapshotCapture {
        stage: HvfArm64SnapshotV1CaptureStage,
        source: Box<HvfVcpuRunnerError>,
    },
    SnapshotRestore {
        stage: HvfArm64SnapshotV1RestoreStage,
        source: Box<HvfVcpuRunnerError>,
    },
    VcpuExitResolve(HvfVcpuExitResolveError),
    MmioDispatch(HvfMmioDispatchError),
    RetainedVtimerWait {
        stage: HvfVcpuRetainedVtimerWaitStage,
        source: Box<HvfVcpuRunnerError>,
    },
    MpidrAffinity {
        stage: HvfVcpuMpidrAffinityStage,
        expected: u64,
        actual: Option<u64>,
        source: Option<BackendError>,
    },
    MpidrAffinityCleanup {
        source: Box<HvfVcpuRunnerError>,
        cleanup: Box<HvfVcpuRunnerError>,
    },
    UnsupportedSys64 {
        exit: HvfSys64Exit,
    },
    InvalidState(&'static str),
    ThreadSpawn(String),
    ChannelClosed(&'static str),
    ThreadPanicked,
}

/// Owner-thread stage for one retained virtual-timer wait failure.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum HvfVcpuRetainedVtimerWaitStage {
    InitialExitMask,
    InitialOffset,
    InitialControl,
    InitialCompareValue,
    InitialCounter,
    Timebase,
    Deadline,
    RecheckExitMask,
    RecheckOffset,
    RecheckControl,
    RecheckCompareValue,
    RecheckCounter,
    Signal,
    PpiPublication,
}

impl fmt::Display for HvfVcpuRetainedVtimerWaitStage {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let name = match self {
            Self::InitialExitMask => "initial virtual-timer exit-mask read",
            Self::InitialOffset => "initial virtual-timer offset read",
            Self::InitialControl => "initial CNTV_CTL_EL0 read",
            Self::InitialCompareValue => "initial CNTV_CVAL_EL0 read",
            Self::InitialCounter => "initial Mach counter sample",
            Self::Timebase => "Mach timebase read",
            Self::Deadline => "virtual-timer deadline calculation",
            Self::RecheckExitMask => "wake virtual-timer exit-mask recheck",
            Self::RecheckOffset => "wake virtual-timer offset recheck",
            Self::RecheckControl => "wake CNTV_CTL_EL0 recheck",
            Self::RecheckCompareValue => "wake CNTV_CVAL_EL0 recheck",
            Self::RecheckCounter => "wake Mach counter recheck",
            Self::Signal => "retained-wait signal arbitration",
            Self::PpiPublication => "virtual-timer PPI publication",
        };
        f.write_str(name)
    }
}

/// Completion of one owner-thread retained virtual-timer wait.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum HvfVcpuRetainedVtimerWaitOutcome {
    /// The admitted timer was due and its selected GIC PPI is pending.
    TimerPending,
    /// Host lifecycle cancellation won before timer publication.
    Canceled,
}

/// Owner-thread stage that failed while assigning one vCPU's MPIDR affinity.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum HvfVcpuMpidrAffinityStage {
    Write,
    Read,
    Verify,
}

impl fmt::Display for HvfVcpuMpidrAffinityStage {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::Write => f.write_str("write"),
            Self::Read => f.write_str("readback"),
            Self::Verify => f.write_str("verification"),
        }
    }
}

/// Value-free reason why a fresh destination is incompatible with native-v1.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum HvfArm64SnapshotV1CompatibilityError {
    Identification,
    OptionalIdentification,
    Mpidr,
}

impl fmt::Display for HvfArm64SnapshotV1CompatibilityError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let category = match self {
            Self::Identification => "baseline identification",
            Self::OptionalIdentification => "optional identification",
            Self::Mpidr => "primary MPIDR",
        };
        write!(f, "native-v1 destination {category} is incompatible")
    }
}

impl std::error::Error for HvfArm64SnapshotV1CompatibilityError {}

