#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum HvfVcpuRunStepOutcome {
    Canceled,
    Hvc {
        exit: HvfHvcExit,
        function_id: u64,
        return_value: u64,
    },
    CpuOff {
        index: usize,
        mpidr: u64,
        exit: HvfHvcExit,
        function_id: u64,
    },
    CpuSuspend {
        index: usize,
        mpidr: u64,
        exit: HvfHvcExit,
        function_id: u64,
    },
    GuestShutdown {
        exit: HvfHvcExit,
        function_id: u64,
        return_value: u64,
    },
    GuestReset {
        exit: HvfHvcExit,
        function_id: u64,
        return_value: u64,
    },
    Sys64 {
        exit: HvfSys64Exit,
    },
    Mmio {
        access: HvfResolvedMmioAccess,
        outcome: MmioDispatchOutcome,
    },
    VtimerActivated,
    Unknown {
        reason: u32,
    },
}

