/// Coordinator-issued identity for one bounded run command.
///
/// The topology coordinator owns token construction. The runner carries the
/// value through its owner thread without interpreting topology identity.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub(crate) struct HvfVcpuRunToken {
    member_index: usize,
    generation: u64,
}

impl HvfVcpuRunToken {
    pub(crate) const fn new(member_index: usize, generation: u64) -> Self {
        Self {
            member_index,
            generation,
        }
    }

    pub(crate) const fn member_index(self) -> usize {
        self.member_index
    }

    pub(crate) const fn generation(self) -> u64 {
        self.generation
    }
}

/// Identified completion published by one owner-thread bounded run.
#[derive(Debug, Clone, PartialEq, Eq)]
pub(crate) struct HvfVcpuRunCompletion {
    token: HvfVcpuRunToken,
    result: Result<HvfVcpuCoordinatedRunStepOutcome, HvfVcpuRunnerError>,
}

impl HvfVcpuRunCompletion {
    pub(crate) const fn new(
        token: HvfVcpuRunToken,
        result: Result<HvfVcpuCoordinatedRunStepOutcome, HvfVcpuRunnerError>,
    ) -> Self {
        Self { token, result }
    }

    pub(crate) fn into_parts(
        self,
    ) -> (
        HvfVcpuRunToken,
        Result<HvfVcpuCoordinatedRunStepOutcome, HvfVcpuRunnerError>,
    ) {
        (self.token, self.result)
    }
}

impl fmt::Display for HvfVcpuRunnerError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::Backend(err) => write!(f, "{err}"),
            Self::CpuTemplate(err) => write!(f, "{err}"),
            Self::Gic(err) => write!(f, "{err}"),
            Self::GicIccRegisterRestore(err) => write!(f, "{err}"),
            Self::DebugTrapRestore(err) => write!(f, "{err}"),
            Self::GeneralRegisterRestore(err) => write!(f, "{err}"),
            Self::PendingInterruptRestore(err) => write!(f, "{err}"),
            Self::SimdFpRestore(err) => write!(f, "{err}"),
            Self::SystemRegisterRestore(err) => write!(f, "{err}"),
            Self::SmePRegisterCapture(err) => write!(f, "{err}"),
            Self::SmeZRegisterCapture(err) => write!(f, "{err}"),
            Self::SmeZaRegisterCapture(err) => write!(f, "{err}"),
            Self::SmeZt0RegisterCapture(err) => write!(f, "{err}"),
            Self::SnapshotTimerPolicy(err) => write!(f, "{err}"),
            Self::SnapshotTimerRestore(err) => write!(f, "{err}"),
            Self::SnapshotOptionalState(err) => write!(f, "{err}"),
            Self::SnapshotRestoreCompatibility(err) => write!(f, "{err}"),
            Self::SnapshotCapture { stage, source } => {
                write!(
                    f,
                    "native-v1 arm64 snapshot capture failed at {stage}: {source}"
                )
            }
            Self::SnapshotRestore { stage, source } => {
                write!(
                    f,
                    "native-v1 arm64 snapshot restore failed at {stage}: {source}"
                )
            }
            Self::VcpuExitResolve(err) => write!(f, "{err}"),
            Self::MmioDispatch(err) => write!(f, "{err}"),
            Self::RetainedVtimerWait { stage, source } => {
                write!(f, "retained virtual-timer wait {stage} failed: {source}")
            }
            Self::MpidrAffinity {
                stage,
                expected,
                actual,
                source,
            } => {
                write!(
                    f,
                    "vCPU MPIDR affinity {stage} failed for expected 0x{expected:x}"
                )?;
                if let Some(actual) = actual {
                    write!(f, ": read back 0x{actual:x}")?;
                }
                if let Some(source) = source {
                    write!(f, ": {source}")?;
                }
                Ok(())
            }
            Self::MpidrAffinityCleanup { source, cleanup } => write!(
                f,
                "vCPU MPIDR affinity setup failed: {source}; runner cleanup also failed: {cleanup}"
            ),
            Self::UnsupportedSys64 { exit } => write!(
                f,
                "unsupported HVF SYS64 {:?} access to {} using Rt {}",
                exit.direction(),
                exit.register(),
                exit.target_register()
            ),
            Self::InvalidState(message) => write!(f, "invalid vCPU runner state: {message}"),
            Self::ThreadSpawn(message) => {
                write!(f, "failed to spawn vCPU runner thread: {message}")
            }
            Self::ChannelClosed(message) => write!(f, "vCPU runner channel closed: {message}"),
            Self::ThreadPanicked => f.write_str("vCPU runner thread panicked"),
        }
    }
}

impl std::error::Error for HvfVcpuRunnerError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            Self::Backend(err) => Some(err),
            Self::CpuTemplate(err) => Some(err),
            Self::Gic(err) => Some(err),
            Self::GicIccRegisterRestore(err) => Some(err),
            Self::DebugTrapRestore(err) => Some(err),
            Self::GeneralRegisterRestore(err) => Some(err),
            Self::PendingInterruptRestore(err) => Some(err),
            Self::SimdFpRestore(err) => Some(err),
            Self::SystemRegisterRestore(err) => Some(err),
            Self::SmePRegisterCapture(err) => Some(err),
            Self::SmeZRegisterCapture(err) => Some(err),
            Self::SmeZaRegisterCapture(err) => Some(err),
            Self::SmeZt0RegisterCapture(err) => Some(err),
            Self::SnapshotTimerPolicy(err) => Some(err),
            Self::SnapshotTimerRestore(err) => Some(err),
            Self::SnapshotOptionalState(err) => Some(err),
            Self::SnapshotRestoreCompatibility(err) => Some(err),
            Self::SnapshotCapture { source, .. } => Some(source.as_ref()),
            Self::SnapshotRestore { source, .. } => Some(source.as_ref()),
            Self::VcpuExitResolve(err) => Some(err),
            Self::MmioDispatch(err) => Some(err),
            Self::RetainedVtimerWait { source, .. } => Some(source.as_ref()),
            Self::MpidrAffinity {
                source: Some(err), ..
            } => Some(err),
            Self::MpidrAffinityCleanup { source, .. } => Some(source.as_ref()),
            Self::InvalidState(_)
            | Self::MpidrAffinity { source: None, .. }
            | Self::UnsupportedSys64 { .. }
            | Self::ThreadSpawn(_)
            | Self::ChannelClosed(_)
            | Self::ThreadPanicked => None,
        }
    }
}

