    fn retained_vtimer_observation(
        control: u64,
        offset: u64,
        compare_value: u64,
        counter: u64,
    ) -> super::RetainedVtimerObservation {
        super::RetainedVtimerObservation {
            _exit_masked: false,
            offset,
            control,
            compare_value,
            counter,
        }
    }

    #[test]
    fn retained_vtimer_deadline_classifies_control_and_wrapping_time() {
        use super::{RetainedVtimerDeadline, classify_retained_vtimer_deadline};

        assert_eq!(
            classify_retained_vtimer_deadline(retained_vtimer_observation(0, 0, 10, 0)),
            Ok(RetainedVtimerDeadline::Indefinite)
        );
        assert_eq!(
            classify_retained_vtimer_deadline(retained_vtimer_observation(0b11, 0, 10, 0)),
            Ok(RetainedVtimerDeadline::Indefinite)
        );
        assert_eq!(
            classify_retained_vtimer_deadline(retained_vtimer_observation(1, 10, 20, 30)),
            Ok(RetainedVtimerDeadline::Due)
        );
        assert_eq!(
            classify_retained_vtimer_deadline(retained_vtimer_observation(1, 10, 20, 25)),
            Ok(RetainedVtimerDeadline::Future { remaining_ticks: 5 })
        );
        assert_eq!(
            classify_retained_vtimer_deadline(retained_vtimer_observation(1, 10, 20, 31)),
            Ok(RetainedVtimerDeadline::Due)
        );
        assert_eq!(
            classify_retained_vtimer_deadline(retained_vtimer_observation(
                1,
                5,
                u64::MAX - 2,
                u64::MAX
            )),
            Ok(RetainedVtimerDeadline::Future { remaining_ticks: 3 })
        );
    }

    #[test]
    fn retained_vtimer_deadline_keeps_large_unsigned_delta_in_the_future() {
        assert_eq!(
            super::classify_retained_vtimer_deadline(retained_vtimer_observation(
                1,
                0,
                1_u64 << 63,
                0
            )),
            Ok(super::RetainedVtimerDeadline::Future {
                remaining_ticks: 1_u64 << 63,
            })
        );
        assert_eq!(
            super::classify_retained_vtimer_deadline(retained_vtimer_observation(
                1,
                0,
                u64::MAX,
                0
            )),
            Ok(super::RetainedVtimerDeadline::Future {
                remaining_ticks: u64::MAX,
            })
        );
    }

    #[test]
    fn retained_vtimer_duration_rounds_up_and_rejects_invalid_ranges() {
        assert_eq!(
            super::retained_vtimer_wait_duration(3, crate::ffi::MachTimebaseInfo::new(2, 3)),
            Ok(Duration::from_nanos(2))
        );
        assert!(matches!(
            super::retained_vtimer_wait_duration(1, crate::ffi::MachTimebaseInfo::new(1, 0)),
            Err(HvfVcpuRunnerError::RetainedVtimerWait {
                stage: super::HvfVcpuRetainedVtimerWaitStage::Deadline,
                source,
            }) if *source == HvfVcpuRunnerError::InvalidState(
                super::RETAINED_VTIMER_INVALID_TIMEBASE_MESSAGE
            )
        ));
        assert!(matches!(
            super::retained_vtimer_wait_duration(1, crate::ffi::MachTimebaseInfo::new(0, 1)),
            Err(HvfVcpuRunnerError::RetainedVtimerWait {
                stage: super::HvfVcpuRetainedVtimerWaitStage::Deadline,
                source,
            }) if *source == HvfVcpuRunnerError::InvalidState(
                super::RETAINED_VTIMER_INVALID_TIMEBASE_MESSAGE
            )
        ));
        assert!(matches!(
            super::retained_vtimer_wait_duration(
                u64::MAX,
                crate::ffi::MachTimebaseInfo::new(u32::MAX, 1)
            ),
            Err(HvfVcpuRunnerError::RetainedVtimerWait {
                stage: super::HvfVcpuRetainedVtimerWaitStage::Deadline,
                source,
            }) if *source == HvfVcpuRunnerError::InvalidState(
                super::RETAINED_VTIMER_DURATION_OVERFLOW_MESSAGE
            )
        ));
    }

    struct SnapshotV1AggregateRecordingVcpu {
        stage_sender: mpsc::Sender<HvfArm64SnapshotV1CaptureStage>,
        restore_stage_sender: Option<mpsc::Sender<HvfArm64SnapshotV1RestoreStage>>,
        destination_cpacr_el1: u64,
        fail_once: Option<HvfArm64SnapshotV1CaptureStage>,
        block_stage: Option<HvfArm64SnapshotV1CaptureStage>,
        entered_sender: Option<mpsc::Sender<()>>,
        release_receiver: Option<mpsc::Receiver<()>>,
    }

    impl SnapshotV1AggregateRecordingVcpu {
        fn record(&mut self, stage: HvfArm64SnapshotV1CaptureStage) -> Result<(), BackendError> {
            self.stage_sender
                .send(stage)
                .map_err(|_| BackendError::InvalidState("snapshot-v1 stage receiver is closed"))?;
            if self.fail_once == Some(stage) {
                self.fail_once = None;
                return Err(BackendError::InvalidState(
                    "injected snapshot-v1 aggregate failure",
                ));
            }
            if self.block_stage == Some(stage) {
                self.entered_sender
                    .as_ref()
                    .ok_or(BackendError::InvalidState(
                        "snapshot-v1 block entry sender is missing",
                    ))?
                    .send(())
                    .map_err(|_| {
                        BackendError::InvalidState("snapshot-v1 block entry receiver is closed")
                    })?;
                self.release_receiver
                    .as_ref()
                    .ok_or(BackendError::InvalidState(
                        "snapshot-v1 block release receiver is missing",
                    ))?
                    .recv()
                    .map_err(|_| {
                        BackendError::InvalidState("snapshot-v1 block release sender is closed")
                    })?;
                self.block_stage = None;
            }
            Ok(())
        }

        fn record_observation(
            &mut self,
            capture: HvfArm64SnapshotV1CaptureStage,
            restore: HvfArm64SnapshotV1RestoreStage,
        ) -> Result<(), BackendError> {
            if let Some(sender) = &self.restore_stage_sender {
                sender.send(restore).map_err(|_| {
                    BackendError::InvalidState("snapshot-v1 restore stage receiver is closed")
                })
            } else {
                self.record(capture)
            }
        }

        fn record_restore(&mut self, stage: HvfArm64SnapshotV1RestoreStage) {
            if let Some(sender) = &self.restore_stage_sender {
                let _ = sender.send(stage);
            }
        }
    }

