    fn shared_dispatcher_with_region() -> Arc<Mutex<MmioDispatcher>> {
        let dispatcher = shared_dispatcher();
        {
            dispatcher
                .lock()
                .expect("dispatcher lock should not be poisoned")
                .insert_region(MmioRegionId::new(7), GuestAddress::new(0x1000), 0x100)
                .expect("test region should insert");
        }
        dispatcher
    }

    fn fake_cancel_vcpu(
        release_run_sender: mpsc::Sender<Result<HvfVcpuExit, BackendError>>,
    ) -> CancelVcpu {
        Arc::new(move |_| {
            release_run_sender
                .send(Ok(HvfVcpuExit::Canceled))
                .map_err(|_| BackendError::InvalidState("fake run release receiver closed"))
        })
    }

    type SnapshotV1AggregateRunnerFixture = (
        HvfVcpuRunner<'static>,
        mpsc::Receiver<HvfArm64SnapshotV1CaptureStage>,
        Option<mpsc::Receiver<()>>,
        Option<mpsc::Sender<()>>,
    );

    fn start_snapshot_v1_aggregate_runner(
        fail_once: Option<HvfArm64SnapshotV1CaptureStage>,
        block_stage: Option<HvfArm64SnapshotV1CaptureStage>,
    ) -> SnapshotV1AggregateRunnerFixture {
        let (stage_sender, stage_receiver) = mpsc::channel();
        let (entered_sender, entered_receiver, release_sender, release_receiver) =
            if block_stage.is_some() {
                let (entered_sender, entered_receiver) = mpsc::channel();
                let (release_sender, release_receiver) = mpsc::channel();
                (
                    Some(entered_sender),
                    Some(entered_receiver),
                    Some(release_sender),
                    Some(release_receiver),
                )
            } else {
                (None, None, None, None)
            };
        let started = spawn_runner_thread(move || {
            Ok(SnapshotV1AggregateRecordingVcpu {
                stage_sender,
                restore_stage_sender: None,
                destination_cpacr_el1: 0,
                fail_once,
                block_stage,
                entered_sender,
                release_receiver,
            })
        })
        .expect("snapshot-v1 aggregate runner should start");
        (
            HvfVcpuRunner::from_started(started, Arc::new(|_| Ok(())))
                .expect("snapshot-v1 aggregate runner should initialize"),
            stage_receiver,
            entered_receiver,
            release_sender,
        )
    }

    fn start_snapshot_v1_restore_runner() -> (
        HvfVcpuRunner<'static>,
        mpsc::Receiver<HvfArm64SnapshotV1RestoreStage>,
    ) {
        start_snapshot_v1_restore_runner_with_cpacr(0)
    }

    fn start_snapshot_v1_restore_runner_with_cpacr(
        destination_cpacr_el1: u64,
    ) -> (
        HvfVcpuRunner<'static>,
        mpsc::Receiver<HvfArm64SnapshotV1RestoreStage>,
    ) {
        let (capture_stage_sender, _capture_stage_receiver) = mpsc::channel();
        let (restore_stage_sender, restore_stage_receiver) = mpsc::channel();
        let started = spawn_runner_thread(move || {
            Ok(SnapshotV1AggregateRecordingVcpu {
                stage_sender: capture_stage_sender,
                restore_stage_sender: Some(restore_stage_sender),
                destination_cpacr_el1,
                fail_once: None,
                block_stage: None,
                entered_sender: None,
                release_receiver: None,
            })
        })
        .expect("snapshot-v1 restore runner should start");
        (
            HvfVcpuRunner::from_started(started, Arc::new(|_| Ok(())))
                .expect("snapshot-v1 restore runner should initialize"),
            restore_stage_receiver,
        )
    }

    fn snapshot_v1_restore_test_state() -> HvfArm64SnapshotV1Restore {
        let (runner, _stages, _, _) = start_snapshot_v1_aggregate_runner(None, None);
        let capture = runner
            .capture_arm64_snapshot_v1_state()
            .expect("source aggregate capture should succeed");
        runner
            .shutdown()
            .expect("source aggregate runner should shut down");
        HvfArm64SnapshotV1Restore::new(
            capture.identification(),
            capture.optional_sve_sme_identification(),
            0x8000_0000,
            capture.vcpu().clone(),
            capture.interrupts().clone(),
        )
    }

    fn start_fake_runner() -> (
        HvfVcpuRunner<'static>,
        mpsc::Receiver<()>,
        mpsc::Receiver<()>,
    ) {
        let (entered_run_sender, entered_run_receiver) = mpsc::channel();
        let (release_run_sender, release_run_receiver) = mpsc::channel();
        let (destroyed_sender, destroyed_receiver) = mpsc::channel();
        let cancel_vcpu = fake_cancel_vcpu(release_run_sender);
        start_fake_runner_with_cancel(
            cancel_vcpu,
            entered_run_sender,
            release_run_receiver,
            destroyed_sender,
            entered_run_receiver,
            destroyed_receiver,
        )
    }

    fn start_dispatch_recording_runner(
        result: Result<MmioDispatchOutcome, HvfVcpuRunnerError>,
    ) -> (
        HvfVcpuRunner<'static>,
        mpsc::Receiver<HvfResolvedMmioAccess>,
    ) {
        let (dispatched_sender, dispatched_receiver) = mpsc::channel();
        let started = spawn_runner_thread(move || {
            Ok(MmioDispatchRecordingVcpu {
                dispatched_sender,
                result,
                pc: 0x8020_2000,
            })
        })
        .expect("fake runner should start");

        (
            HvfVcpuRunner::from_started(started, Arc::new(|_| Ok(())))
                .expect("runner should be created"),
            dispatched_receiver,
        )
    }

    fn start_run_step_recording_runner(
        run_once_result: Result<HvfVcpuExit, BackendError>,
        dispatch_result: Result<MmioDispatchOutcome, HvfVcpuRunnerError>,
    ) -> (
        HvfVcpuRunner<'static>,
        mpsc::Receiver<HvfResolvedMmioAccess>,
        mpsc::Receiver<(HvfRegister, u64)>,
    ) {
        let (dispatched_sender, dispatched_receiver) = mpsc::channel();
        let (register_write_sender, register_write_receiver) = mpsc::channel();
        let started = spawn_runner_thread(move || {
            Ok(RunStepRecordingVcpu {
                run_once_result,
                dispatched_sender: Some(dispatched_sender),
                dispatch_result,
                pc: 0x8020_3000,
                register_write_sender,
            })
        })
        .expect("fake runner should start");

        (
            HvfVcpuRunner::from_started(started, Arc::new(|_| Ok(())))
                .expect("runner should be created"),
            dispatched_receiver,
            register_write_receiver,
        )
    }

