    #[test]
    fn every_arm64_system_context_register_restore_failure_is_typed_and_retryable() {
        use std::error::Error as _;

        let state = system_context_register_restore_test_state();
        let expected = system_context_register_restore_test_entries();

        for (failed_index, (failed_register, _)) in expected.iter().copied().enumerate() {
            let (runner, write_receiver) =
                start_system_context_register_restore_recording_runner(Some(failed_register));

            let error = runner
                .restore_arm64_system_context_register_state(&state)
                .expect_err("injected system-context register write should fail");
            let HvfVcpuRunnerError::SystemRegisterRestore(error) = error else {
                panic!("restore failure should retain its typed context");
            };
            assert_eq!(error.failed_register(), failed_register);
            assert_eq!(error.completed_writes(), failed_index);
            assert_eq!(
                error.source().map(ToString::to_string),
                Some(
                    "invalid backend state: fake system-context register restore failed"
                        .to_string()
                )
            );
            assert_eq!(
                error.to_string(),
                format!(
                    "failed to restore arm64 system register id {} after {failed_index} successful writes: invalid backend state: fake system-context register restore failed",
                    failed_register.raw()
                )
            );
            assert_eq!(
                write_receiver.try_iter().collect::<Vec<_>>(),
                expected[..=failed_index]
            );

            runner
                .restore_arm64_system_context_register_state(&state)
                .expect("complete system-context register restore retry should succeed");
            assert_eq!(write_receiver.try_iter().collect::<Vec<_>>(), expected);
            assert_eq!(runner.run_once(), Ok(HvfVcpuExit::Canceled));

            runner.shutdown().expect("runner should shut down");
        }
    }

