    #[test]
    fn run_once_and_handle_mmio_dispatches_mmio_exit_on_runner_thread() {
        let access = resolved_mmio_access();
        let (runner, dispatched_receiver, register_write_receiver) =
            start_run_step_recording_runner(
                Ok(mmio_exception_exit()),
                Ok(MmioDispatchOutcome::Write),
            );
        let dispatcher = shared_dispatcher_with_region();

        assert_eq!(
            runner.run_once_and_handle_mmio(Arc::clone(&dispatcher)),
            Ok(HvfVcpuRunStepOutcome::Mmio {
                access,
                outcome: MmioDispatchOutcome::Write,
            })
        );
        assert_eq!(
            dispatched_receiver
                .recv()
                .expect("fake vCPU should receive dispatch"),
            access
        );
        assert_eq!(
            register_write_receiver
                .recv()
                .expect("fake vCPU should advance PC"),
            (HvfRegister::PC, 0x8020_3004)
        );
        let region_ids = dispatcher
            .lock()
            .expect("dispatcher lock should not be poisoned")
            .regions()
            .iter()
            .map(|region| region.id())
            .collect::<Vec<_>>();
        assert_eq!(
            region_ids,
            vec![MmioRegionId::new(7), MmioRegionId::new(99)]
        );

        runner.shutdown().expect("runner should shut down");
    }

    #[test]
    fn run_once_and_handle_mmio_returns_non_mmio_exits_without_dispatcher_lock() {
        for (exit, outcome) in [
            (HvfVcpuExit::Canceled, HvfVcpuRunStepOutcome::Canceled),
            (
                HvfVcpuExit::VtimerActivated,
                HvfVcpuRunStepOutcome::VtimerActivated,
            ),
            (
                HvfVcpuExit::Unknown { reason: 99 },
                HvfVcpuRunStepOutcome::Unknown { reason: 99 },
            ),
        ] {
            let runner = start_run_step_exit_runner(Ok(exit));
            let dispatcher = shared_dispatcher();
            let dispatcher_guard = dispatcher
                .lock()
                .expect("dispatcher lock should not be poisoned");

            assert_eq!(
                runner.run_once_and_handle_mmio(Arc::clone(&dispatcher)),
                Ok(outcome)
            );
            drop(dispatcher_guard);

            runner.shutdown().expect("runner should shut down");
        }
    }

    #[test]
    fn coordinated_cpu_suspend_wait_preserves_x0_until_identified_timer_wakeup() {
        for function_id in [PSCI_CPU_SUSPEND, PSCI_CPU_SUSPEND_64] {
            let arguments = [0xfeed_face, 0x1234_5678_9abc_def0, u64::MAX];
            let (runner, register_reads, register_writes, timer_samples, ppi) =
                start_cpu_suspend_retained_runner(function_id, arguments, 1, 100, [Ok(100)]);
            let HvfVcpuCoordinatedRunStepOutcome::Psci {
                token: psci_token,
                request: PsciCoordinatorRequest::CpuSuspend,
                ..
            } = runner
                .run_once_and_handle_mmio_coordinated(shared_dispatcher())
                .expect("CPU_SUSPEND should defer")
            else {
                panic!("CPU_SUSPEND should return typed coordinator work");
            };
            assert_eq!(
                register_reads.try_iter().collect::<Vec<_>>(),
                vec![
                    HvfRegister::X0,
                    HvfRegister::X1,
                    HvfRegister::X2,
                    HvfRegister::X3,
                ]
            );
            assert_eq!(register_writes.try_recv(), Err(mpsc::TryRecvError::Empty));

            let run_token = HvfVcpuRunToken::new(0, 7);
            let (completion_sender, completion_receiver) = mpsc::channel();
            runner
                .submit_psci_cpu_suspend_wait_coordinated(
                    run_token,
                    psci_token,
                    27,
                    completion_sender,
                )
                .expect("exact CPU_SUSPEND wait should submit");
            timer_samples
                .recv()
                .expect("retained timer should be sampled");
            let (actual_run_token, result) = completion_receiver
                .recv()
                .expect("retained timer completion should publish")
                .into_parts();
            assert_eq!(actual_run_token, run_token);
            assert_eq!(
                result,
                Ok(HvfVcpuCoordinatedRunStepOutcome::RetainedVtimer {
                    psci_token,
                    outcome: super::HvfVcpuRetainedVtimerWaitOutcome::TimerPending,
                })
            );
            assert_eq!(
                ppi.recv().expect("timer completion should publish its PPI"),
                (27, true)
            );
            assert_eq!(register_writes.try_recv(), Err(mpsc::TryRecvError::Empty));

            runner
                .complete_psci_call(
                    psci_token,
                    PsciCoordinatorResponse::CpuSuspend(PsciCpuSuspendResponse::Success),
                )
                .expect("timer wake should complete CPU_SUSPEND");
            assert_eq!(
                register_writes
                    .recv()
                    .expect("CPU_SUSPEND completion should write X0"),
                (HvfRegister::X0, PSCI_RET_SUCCESS)
            );
            runner.shutdown().expect("runner should shut down");
        }
    }

    #[test]
    fn coordinated_cpu_suspend_wait_rejects_stale_and_wrong_requests() {
        let (runner, _, register_writes) = start_coordinated_psci_run_step_recording_runner(
            PSCI_CPU_ON,
            [1, 0x8020_0000, 0],
            0,
            false,
        );
        let HvfVcpuCoordinatedRunStepOutcome::Psci {
            token: psci_token, ..
        } = runner
            .run_once_and_handle_mmio_coordinated(shared_dispatcher())
            .expect("CPU_ON should defer")
        else {
            panic!("CPU_ON should return coordinator work");
        };
        let stale = HvfVcpuPsciCallToken {
            vcpu: psci_token.vcpu,
            sequence: psci_token.sequence + 1,
        };
        let (completion_sender, _completion_receiver) = mpsc::channel();
        assert_eq!(
            runner.submit_psci_cpu_suspend_wait_coordinated(
                HvfVcpuRunToken::new(0, 1),
                stale,
                27,
                completion_sender,
            ),
            Err(HvfVcpuRunnerError::InvalidState(
                super::PSCI_CALL_TOKEN_MISMATCH_MESSAGE
            ))
        );

        let (completion_sender, completion_receiver) = mpsc::channel();
        runner
            .submit_psci_cpu_suspend_wait_coordinated(
                HvfVcpuRunToken::new(0, 2),
                psci_token,
                27,
                completion_sender,
            )
            .expect("exact token should reach owner validation");
        let (_, result) = completion_receiver
            .recv()
            .expect("wrong request should publish an identified error")
            .into_parts();
        assert_eq!(
            result,
            Err(HvfVcpuRunnerError::InvalidState(
                super::PSCI_CALL_REQUEST_MISMATCH_MESSAGE
            ))
        );
        assert_eq!(register_writes.try_recv(), Err(mpsc::TryRecvError::Empty));
        runner
            .complete_psci_call(
                psci_token,
                PsciCoordinatorResponse::CpuOn(PsciCpuOnResponse::InternalFailure),
            )
            .expect("original CPU_ON should remain completable");
        runner.shutdown().expect("runner should shut down");
    }

    #[test]
    fn canceled_cpu_suspend_wait_retains_exact_transaction_for_rearm() {
        let (runner, _, register_writes, timer_samples, _ppi) =
            start_cpu_suspend_retained_runner(PSCI_CPU_SUSPEND, [1, 2, 3], 0, 100, [Ok(1), Ok(2)]);
        let HvfVcpuCoordinatedRunStepOutcome::Psci {
            token: psci_token, ..
        } = runner
            .run_once_and_handle_mmio_coordinated(shared_dispatcher())
            .expect("CPU_SUSPEND should defer")
        else {
            panic!("CPU_SUSPEND should return coordinator work");
        };
        let cancel = runner.run_cancel_handle();

        for generation in [1, 2] {
            let run_token = HvfVcpuRunToken::new(0, generation);
            let (completion_sender, completion_receiver) = mpsc::channel();
            runner
                .submit_psci_cpu_suspend_wait_coordinated(
                    run_token,
                    psci_token,
                    27,
                    completion_sender,
                )
                .expect("CPU_SUSPEND wait should rearm");
            timer_samples
                .recv()
                .expect("rearmed wait should sample the timer");
            cancel.cancel().expect("rearmed wait should cancel");
            let (actual_token, result) = completion_receiver
                .recv()
                .expect("canceled wait should publish")
                .into_parts();
            assert_eq!(actual_token, run_token);
            assert_eq!(
                result,
                Ok(HvfVcpuCoordinatedRunStepOutcome::RetainedVtimer {
                    psci_token,
                    outcome: super::HvfVcpuRetainedVtimerWaitOutcome::Canceled,
                })
            );
            assert_eq!(register_writes.try_recv(), Err(mpsc::TryRecvError::Empty));
        }

        runner.shutdown().expect("runner should shut down");
    }

    #[test]
    fn coordinated_cpu_on_captures_x1_through_x3_without_writing_caller_x0() {
        let arguments = [1, 0x0000_0001_8020_0000, 0xfeed_face_cafe_beef];
        let (runner, register_read_receiver, register_write_receiver) =
            start_coordinated_psci_run_step_recording_runner(PSCI_CPU_ON_64, arguments, 0, false);

        let outcome = runner
            .run_once_and_handle_mmio_coordinated(shared_dispatcher())
            .expect("CPU_ON should defer to the coordinator");
        let HvfVcpuCoordinatedRunStepOutcome::Psci {
            exit,
            function_id,
            token: _,
            request: PsciCoordinatorRequest::CpuOn(request),
        } = outcome
        else {
            panic!("CPU_ON should return typed coordinator work");
        };
        assert_eq!(exit, hvc_exit(0));
        assert_eq!(function_id, PSCI_CPU_ON_64);
        assert_eq!(request.target_mpidr(), arguments[0]);
        assert_eq!(request.entry_point(), arguments[1]);
        assert_eq!(request.context_id(), arguments[2]);
        assert_eq!(
            register_read_receiver.try_iter().collect::<Vec<_>>(),
            vec![
                HvfRegister::X0,
                HvfRegister::X1,
                HvfRegister::X2,
                HvfRegister::X3,
            ]
        );
        assert_eq!(
            register_write_receiver.try_recv(),
            Err(mpsc::TryRecvError::Empty)
        );

        assert_eq!(
            runner.run_once(),
            Err(HvfVcpuRunnerError::InvalidState(
                super::PSCI_CALL_PENDING_MESSAGE
            ))
        );
        assert_eq!(
            runner.run_once_and_handle_mmio(shared_dispatcher()),
            Err(HvfVcpuRunnerError::InvalidState(
                super::PSCI_CALL_PENDING_MESSAGE
            ))
        );
        assert_eq!(
            runner.run_once_and_handle_mmio_coordinated(shared_dispatcher()),
            Err(HvfVcpuRunnerError::InvalidState(
                super::PSCI_CALL_PENDING_MESSAGE
            ))
        );
        assert_eq!(
            runner.dispatch_mmio_access(resolved_mmio_access(), shared_dispatcher()),
            Err(HvfVcpuRunnerError::InvalidState(
                super::PSCI_CALL_PENDING_MESSAGE
            ))
        );
        assert_eq!(
            runner.capture_arm64_general_register_state(),
            Err(HvfVcpuRunnerError::InvalidState(
                super::PSCI_CALL_PENDING_MESSAGE
            ))
        );

        runner
            .shutdown()
            .expect("abandoned deferred caller should still shut down");
        assert_eq!(
            register_write_receiver.try_recv(),
            Err(mpsc::TryRecvError::Disconnected)
        );
    }

    #[test]
    fn coordinated_cpu_off_commits_without_x0_and_reopens_secondary_execution_epoch() {
        let (runner, register_read_receiver, register_write_receiver) =
            start_coordinated_psci_run_step_recording_runner(PSCI_CPU_OFF, [u64::MAX; 3], 0, false);
        let registers =
            HvfArm64SecondaryBootRegisters::new(GuestAddress::new(0x8020_0000), 0xfeed_face);

        for cycle in 0..2 {
            let HvfVcpuCoordinatedRunStepOutcome::Psci {
                token,
                request: PsciCoordinatorRequest::CpuOff,
                ..
            } = runner
                .run_once_and_handle_mmio_coordinated(shared_dispatcher())
                .expect("CPU_OFF should defer")
            else {
                panic!("CPU_OFF should return typed coordinator work");
            };
            assert_eq!(
                runner.configure_arm64_secondary_boot_registers(registers),
                Err(HvfVcpuRunnerError::InvalidState(
                    super::PSCI_CALL_PENDING_MESSAGE
                ))
            );
            runner
                .commit_psci_cpu_off(token)
                .expect("CPU_OFF should commit without a response");
            assert_eq!(
                register_write_receiver.try_recv(),
                Err(mpsc::TryRecvError::Empty),
                "CPU_OFF cycle {cycle} must not write X0"
            );
            runner
                .configure_arm64_secondary_boot_registers(registers)
                .expect("committed CPU_OFF should open the next entry epoch");
        }
        assert_eq!(
            register_read_receiver.try_iter().collect::<Vec<_>>(),
            vec![HvfRegister::X0, HvfRegister::X0]
        );

        runner.shutdown().expect("runner should shut down");
    }

